define i32 @add_constant_equal_with_the_top_bit_of_demandedbits_insertpt(i32 %x, i32 %y) {
  %add = add i32 %x, 16
  %or = or i32 %add, %y
  %and = and i32 %or, 24
  ret i32 %and
}

define <2 x i32> @and_add_bool_vec_to_select(<2 x i1> %x, <2 x i32> %y) {
  %val = zext <2 x i1> %x to <2 x i32>
  %mask = add <2 x i32> <i32 -1, i32 -1>, %val
  %res = and <2 x i32> %mask, %y
  ret <2 x i32> %res
}
